int main() {
    int n;
    scanf("%d", &n);
    long long a = 1, b = 1, total = 0;
    for (int i = 0; i < n; i++) {
        total += a;
        long long tmp = a + b;
        a = b;
        b = tmp;
    }
    printf("%lld\n", total);
    return 0;
